            <button
              type="button"
              onClick={generateReport}
              className="px-6 py-2 bg-green-600 text-white rounded-md shadow-sm hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-green-500"
            >
              GENERATE REPORT (PDF)
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

